class Solution {
    public int clumsy(int n) {
        int result = 1;
        for (int I = n; I >= 1; i--) {
            result = (result * i) / 10 + (result * 9) / 5 + (result * 8) / 4 + (result * 7) / 3 - (result * 6) / 2 - (result * 5) / 1;
        }
        return result;
    }
}
